'stats-skills':{t:'10,000+ Skill Categories',b:`<p style="color:#617a5a;font-size:14px;line-height:1.75;margin-bottom:20px">Remoworkers covers every professional skill imaginable — from niche software stacks to highly specialized legal and engineering domains.</p><div class="skills-cloud" style="margin-top:0"><span class="sk-pill hot" onclick="openModal('skill-react')">React</span><span class="sk-pill hot" onclick="openModal('skill-python')">Python</span><span class="sk-pill" onclick="openModal('skill-ai')">LLMs</span><span class="sk-pill" onclick="openModal('skill-figma')">Figma</span><span class="sk-pill" onclick="openModal('skill-seo')">SEO</span><span class="sk-pill">Terraform</span><span class="sk-pill">Rust</span><span class="sk-pill">Solidity</span><span class="sk-pill">Unity</span><span class="sk-pill">Blender</span></div><div class="modal-actions" style="margin-top:20px"><button class="btn btn-green btn-full" onclick="closeModal()">See All Skills ↓</button></div>`},
'stats-paid':{t:'$2B+ Paid to Freelancers',b:`<div class="cat-stats-row"><div class="cs"><div class="cs-n">$2B+</div><div class="cs-l">Total paid out</div></div><div class="cs"><div class="cs-n">190+</div><div class="cs-l">Payout currencies</div></div><div class="cs"><div class="cs-n">$0</div><div class="cs-l">Payment failures</div></div></div><p style="color:#617a5a;font-size:14px;line-height:1.75;margin-bottom:20px">Remoworkers has processed over $2 billion in freelancer payments with zero payment failures. Freelancers can withdraw via bank transfer, PayPal, Payoneer, wire transfer, or local payment methods in 190+ countries.</p><div class="modal-actions"><button class="btn btn-green btn-full" onclick="openModal('trust-safety')">How payments work →</button></div>`},
