const NM = {
'uma-scout':{t:'Uma™ Recruiter Shortlisting',b:`<div style="background:#16281a;border-radius:20px;padding:24px;margin-bottom:24px"><div style="display:flex;align-items:center;gap:12px;margin-bottom:14px"><div style="font-size:36px">🎯</div><div><h3 style="font-family:'Instrument Serif',serif;font-size:20px;color:#c8f135;margin-bottom:4px">Uma™ automatically finds your best matches</h3><div style="background:#c8f135;color:#16281a;font-size:10px;font-weight:700;padding:2px 8px;border-radius:10px;display:inline-block">Available on all plans</div></div></div><p style="color:rgba(255,255,255,.65);font-size:14px;line-height:1.7">As soon as you post a job, Uma analyzes your brief and automatically surfaces the most relevant freelancers — ranked by skill match, past performance, and project type. No manual searching required.</p></div><div class="cat-stats-row"><div class="cs"><div class="cs-n">&lt;2min</div><div class="cs-l">Time to first match</div></div><div class="cs"><div class="cs-n">Top 5</div><div class="cs-l">Curated candidates</div></div><div class="cs"><div class="cs-n">94%</div><div class="cs-l">Client satisfaction</div></div></div><div class="cat-modal-jobs"><div class="job-item" style="cursor:default"><div class="job-item-ico">🤖</div><div class="job-item-body"><h4>How it works</h4><p>Post your job → Uma reads your description → Instantly identifies the top-ranked matches from 5M+ freelancers → Sends you a curated shortlist with work history summaries.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">📊</div><div class="job-item-body"><h4>What Uma considers</h4><p>Skill match, past project similarity, client satisfaction score, response rate, availability, location, rate fit, and Uma-generated compatibility score — all weighed against your specific brief.</p></div></div></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="openModal('post-job')">Post a job and get matched →</button></div>`},
'uma-history':{t:'Uma™ Work History Summaries',b:`<div style="background:#16281a;border-radius:20px;padding:24px;margin-bottom:24px"><div style="font-size:36px;margin-bottom:12px">📋</div><h3 style="font-family:'Instrument Serif',serif;font-size:20px;color:#c8f135;margin-bottom:8px">Compare candidates in seconds, not hours</h3><p style="color:rgba(255,255,255,.65);font-size:14px;line-height:1.7">Uma automatically synthesizes each freelancer's most relevant past work into a short, scannable summary — so you can objectively compare 5 candidates in the time it used to take to read one full profile.</p></div><div style="background:#f7faf5;border:1.5px solid #dce8d8;border-radius:16px;padding:20px;margin-bottom:20px"><div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:#8aa082;margin-bottom:12px">Uma-Generated Summary — Anika Nkosi</div><p style="font-size:14px;color:#333;line-height:1.75;font-style:italic">"Anika has completed 14 UI/UX projects closely matching your brief — 9 involved SaaS dashboard redesigns, 4 were design system builds, and 2 were Webflow-based. Average delivery time: 6 days. All received 5-star ratings. Client industry overlap: 71% fintech and B2B SaaS."</p><div style="display:flex;gap:8px;margin-top:12px"><span style="background:#e8f5e3;color:#0a6b00;font-size:11px;font-weight:700;padding:3px 10px;border-radius:10px">High relevance match</span><span style="background:#dbeafe;color:#1e40af;font-size:11px;font-weight:700;padding:3px 10px;border-radius:10px">Fast deliverer</span><span style="background:#ede9fe;color:#5b21b6;font-size:11px;font-weight:700;padding:3px 10px;border-radius:10px">SaaS specialist</span></div></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="openModal('talent-marketplace')">See talent with Uma summaries →</button></div>`},
'uma-contract':{t:'Uma™ In-Meeting Contract Generator',b:`<div style="background:#16281a;border-radius:20px;padding:24px;margin-bottom:24px"><div style="font-size:36px;margin-bottom:12px">📝</div><h3 style="font-family:'Instrument Serif',serif;font-size:20px;color:#c8f135;margin-bottom:8px">From video call to signed contract in minutes</h3><p style="color:rgba(255,255,255,.65);font-size:14px;line-height:1.7">Uma listens to your Remoworkers video meeting, captures key details like scope, timeline, budget, and deliverables, then generates a ready-to-review contract draft automatically.</p></div><div class="cat-modal-jobs"><div class="job-item" style="cursor:default"><div class="job-item-ico">📹</div><div class="job-item-body"><h4>Step 1: Have your meeting</h4><p>Start a Remoworkers video call with your candidate. Discuss scope, timeline, budget, and any project specifics. Uma listens with your permission.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">🤖</div><div class="job-item-body"><h4>Step 2: Uma drafts your contract</h4><p>Within 2 minutes of ending the call, Uma generates a full contract draft including milestones, payment terms, IP assignment, and NDA clauses.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">✍️</div><div class="job-item-body"><h4>Step 3: Review & send for signature</h4><p>Edit any detail in the draft, then send to your freelancer with one click. E-signatures collected instantly. Contract stored securely in your dashboard.</p></div></div></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="openModal('video-meetings')">Try a video meeting →</button></div>`},
'uma-diary':{t:'Work Diary & Uma™ Summaries',b:`<div class="cat-stats-row"><div class="cs"><div class="cs-n">10min</div><div class="cs-l">Screenshot interval</div></div><div class="cs"><div class="cs-n">Daily</div><div class="cs-l">Uma summaries</div></div><div class="cs"><div class="cs-n">100%</div><div class="cs-l">Hourly contract verified</div></div></div><p style="color:#617a5a;font-size:14px;line-height:1.75;margin-bottom:20px">For hourly contracts, Remoworkers's time tracker automatically captures activity logs every 10 minutes — screenshots, keyboard activity, and mouse movement. Uma summarizes everything into clear daily and weekly progress reports so you always know what's happening without micromanaging.</p><div style="background:#f7faf5;border:1.5px solid #dce8d8;border-radius:16px;padding:20px;margin-bottom:20px"><div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:#8aa082;margin-bottom:12px">Uma's Daily Summary — James Kowalski · Today</div><p style="font-size:14px;color:#333;line-height:1.75;font-style:italic">"James logged 6.5 hours today. Primary focus: building the PostgreSQL schema and REST API endpoints (approx 4h). Secondary: writing unit tests for auth flow (approx 2.5h). 3 code commits pushed to GitHub. On track with milestone 1 due Friday."</p></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="openModal('post-job')">Start a hourly contract →</button></div>`},
'uma-continuity':{t:'Project Continuity — Uma™',b:`<div style="background:#16281a;border-radius:20px;padding:24px;margin-bottom:24px"><div style="font-size:36px;margin-bottom:12px">🔄</div><h3 style="font-family:'Instrument Serif',serif;font-size:20px;color:#c8f135;margin-bottom:8px">Projects don't stop when hires change</h3><p style="color:rgba(255,255,255,.65);font-size:14px;line-height:1.7">If a hire doesn't work out, Uma preserves everything — project context, prior work, goals, and deliverables — and surfaces a new shortlist of candidates who can pick up exactly where things left off.</p></div><div class="cat-modal-jobs"><div class="job-item" style="cursor:default"><div class="job-item-ico">💾</div><div class="job-item-body"><h4>Project context is preserved</h4><p>All messages, files, deliverables, scope notes, and Uma summaries are retained and passed to the replacement candidate brief automatically.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">🎯</div><div class="job-item-body"><h4>Uma finds replacement candidates</h4><p>Uma immediately shortlists 3–5 replacement candidates matched to the original brief — so you can re-hire and resume within hours, not weeks.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">⚡</div><div class="job-item-body"><h4>Zero disruption to your timeline</h4><p>Most clients using Project Continuity resume active work within 24 hours of a replacement hire. Business Plus clients get priority replacement matching.</p></div></div></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="openModal('enterprise')">Available on Business Plus →</button></div>`},
'uma-chatgpt':{t:'Remoworkers in ChatGPT',b:`<div style="background:#16281a;border-radius:20px;padding:28px;text-align:center;margin-bottom:24px"><div style="font-size:48px;margin-bottom:12px">🤖</div><h3 style="font-family:'Instrument Serif',serif;font-size:22px;color:#c8f135;margin-bottom:8px">Find talent without leaving ChatGPT</h3><p style="color:rgba(255,255,255,.65);font-size:14px;line-height:1.7">The Remoworkers app for ChatGPT lets you describe your project in natural language, discover relevant talent, draft a job post, and even post it — all directly inside ChatGPT.</p></div><div class="cat-modal-jobs"><div class="job-item" style="cursor:default"><div class="job-item-ico">💬</div><div class="job-item-body"><h4>Start in ChatGPT</h4><p>Type "I need a React developer for a 2-week dashboard project with a $5K budget" and the Remoworkers app automatically searches talent, shows profiles, and helps draft your job post.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">🔍</div><div class="job-item-body"><h4>Discover vetted talent instantly</h4><p>Get matched profiles with ratings, rates, and availability shown inline in your ChatGPT conversation — no tab-switching required.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">📋</div><div class="job-item-body"><h4>Post your job with one command</h4><p>Approve the drafted job post from ChatGPT and it publishes live to Remoworkers instantly, ready to receive proposals within hours.</p></div></div></div><div class="modal-actions"><button class="btn btn-dark btn-full" onclick="showToast('Opening ChatGPT','Install the Remoworkers app from the ChatGPT plugin store')">Open in ChatGPT</button></div>`},
'video-meetings':{t:'Remoworkers Video Meetings',b:`<div class="cat-stats-row"><div class="cs"><div class="cs-n">HD</div><div class="cs-l">Video quality</div></div><div class="cs"><div class="cs-n">&lt;2min</div><div class="cs-l">AI recap ready</div></div><div class="cs"><div class="cs-n">100%</div><div class="cs-l">Encrypted</div></div></div><p style="color:#617a5a;font-size:14px;line-height:1.75;margin-bottom:20px">Remoworkers has a full built-in video calling system — no Zoom, no Google Meet. Every call includes AI-generated transcripts, instant meeting recaps, and Uma's in-meeting contract generator.</p><div class="cat-modal-jobs"><div class="job-item" style="cursor:default"><div class="job-item-ico">📹</div><div class="job-item-body"><h4>HD Video Meetings</h4><p>Crystal-clear HD video with screen sharing, file sharing in-call, and waiting rooms. Now fully mobile compatible on iOS and Android.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">📄</div><div class="job-item-body"><h4>AI Transcript & Recap</h4><p>Uma produces a full searchable transcript and a 3-paragraph meeting recap within 2 minutes of every call ending. Shared with both parties automatically.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">✍️</div><div class="job-item-body"><h4>In-Meeting Contract Generator</h4><p>Uma uses the meeting transcript to draft a contract — scope, milestones, payment, IP terms — ready to review and send for e-signature.</p></div></div></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="showToast('Video call started','Opening Remoworkers meeting room...')">Start a Video Meeting</button></div>`},
'direct-contract':{t:'Direct Contracts',b:`<div style="background:#f7faf5;border:1.5px solid #dce8d8;border-radius:16px;padding:24px;margin-bottom:24px"><h3 style="font-size:17px;font-weight:700;margin-bottom:8px">Already found someone? Bring them onto Remoworkers.</h3><p style="font-size:14px;color:#617a5a;line-height:1.75">Direct Contracts lets you work with any freelancer — even if they're not on Remoworkers yet — while still getting full escrow payment protection, time tracking, and dispute resolution.</p></div><div class="cat-modal-jobs"><div class="job-item" style="cursor:default"><div class="job-item-ico">🔗</div><div class="job-item-body"><h4>Invite any freelancer</h4><p>Send your freelancer a Direct Contract invite link. They sign up for free and accept the contract terms — no platform experience needed.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">🛡️</div><div class="job-item-body"><h4>Full payment protection</h4><p>Funds are held in Remoworkers escrow just like any other contract. Only released when you approve the work — same guarantee, no exceptions.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">💳</div><div class="job-item-body"><h4>0% platform fee option</h4><p>Direct Contracts are available with a flat monthly fee instead of a percentage fee — ideal for long-term, high-value engagements.</p></div></div></div><div class="form-group" style="margin-top:16px"><label>Freelancer's email address</label><input type="email" placeholder="your-freelancer@email.com"></div><div class="form-group"><label>Contract value</label><input type="number" placeholder="e.g. 5000"></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="showToast('Direct Contract sent!','Your freelancer has been sent an invitation to join Remoworkers')">Send Direct Contract Invite</button></div>`},
'connects':{t:'Connects — How They Work',b:`<div style="background:#f7faf5;border:1.5px solid #dce8d8;border-radius:16px;padding:24px;margin-bottom:24px"><h3 style="font-size:17px;font-weight:700;margin-bottom:8px">What are Connects?</h3><p style="font-size:14px;color:#617a5a;line-height:1.75">Connects are Remoworkers's lightweight application token. Freelancers spend Connects to apply for jobs — this filters out mass-spammers and signals genuine interest to clients.</p></div><div class="cat-stats-row"><div class="cs"><div class="cs-n">Tokens</div><div class="cs-l">Per Connect</div></div><div class="cs"><div class="cs-n">1–6</div><div class="cs-l">Connects per application</div></div><div class="cs"><div class="cs-n">Free</div><div class="cs-l">For clients to post jobs</div></div></div><div class="cat-modal-jobs"><div class="job-item" style="cursor:default"><div class="job-item-ico">💎</div><div class="job-item-body"><h4>Bundles available</h4><p>Purchase Connects in varying bundles. Business Plus subscribers get a monthly Connects allowance included.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">🔄</div><div class="job-item-body"><h4>Get Connects back</h4><p>If a client closes a job without hiring or if they archive it, unused Connects are returned to your balance automatically within 24 hours.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">🎁</div><div class="job-item-body"><h4>Free Connects to start</h4><p>New freelancers get 20 free Connects on signup. Refer a friend who gets their first contract and earn 10 more.</p></div></div></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="showToast('Signup to buy', 'Create a freelancer account to purchase Connects')">Signup to Buy Connects</button></div>`},
'bonus-tip':{t:'Send a Bonus or Tip',b:`<div style="background:#f7faf5;border:1.5px solid #dce8d8;border-radius:16px;padding:22px;margin-bottom:24px"><p style="font-size:14px;color:#617a5a;line-height:1.75">Did your freelancer go above and beyond? Send them a bonus on top of the contract payment. Bonuses help build strong long-term relationships, improve your client reputation, and are often reciprocated with priority service on future projects.</p></div><div class="form-group"><label>Select a contract</label><select><option>React Dashboard — James Kowalski (ongoing)</option><option>Logo Design — Anika Nkosi (completed)</option><option>SEO Strategy — Lena Thornton (completed)</option></select></div><div class="form-group"><label>Bonus amount ($)</label><input type="number" placeholder="e.g. 100"></div><div class="form-group"><label>Message to freelancer (optional)</label><textarea placeholder="e.g. You went above and beyond on this project — really appreciate the extra care on the design details." style="min-height:80px"></textarea></div><div style="display:flex;gap:10px;margin-bottom:18px"><div onclick="this.parentElement.querySelectorAll('div').forEach(b=>b.classList.remove('sel'));this.classList.add('sel')" style="flex:1;border:1.5px solid #dce8d8;border-radius:12px;padding:12px;cursor:pointer;text-align:center;font-size:13px;font-weight:600"><div style="font-size:20px;margin-bottom:4px">☕</div>$25</div><div onclick="this.parentElement.querySelectorAll('div').forEach(b=>b.classList.remove('sel'));this.classList.add('sel')" style="flex:1;border:1.5px solid #14a800;border-radius:12px;padding:12px;cursor:pointer;text-align:center;font-size:13px;font-weight:600;background:#e8f5e3;color:#0a6b00"><div style="font-size:20px;margin-bottom:4px">🎁</div>$50</div><div onclick="this.parentElement.querySelectorAll('div').forEach(b=>b.classList.remove('sel'));this.classList.add('sel')" style="flex:1;border:1.5px solid #dce8d8;border-radius:12px;padding:12px;cursor:pointer;text-align:center;font-size:13px;font-weight:600"><div style="font-size:20px;margin-bottom:4px">⭐</div>$100</div><div onclick="this.parentElement.querySelectorAll('div').forEach(b=>b.classList.remove('sel'));this.classList.add('sel')" style="flex:1;border:1.5px solid #dce8d8;border-radius:12px;padding:12px;cursor:pointer;text-align:center;font-size:13px;font-weight:600"><div style="font-size:20px;margin-bottom:4px">🏆</div>Custom</div></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="showToast('Bonus sent! 🎉','Your freelancer has been notified and will receive the payment within 24hrs')">Send Bonus</button></div>`},
'certifications':{t:'Skill Assessments & Certifications',b:`<p style="color:#617a5a;font-size:14px;line-height:1.75;margin-bottom:20px">Take proctored skill assessments to earn verified badges that appear on your profile. Certified freelancers receive 60% more invitations from clients.</p><div class="cat-stats-row"><div class="cs"><div class="cs-n">150+</div><div class="cs-l">Skill tests available</div></div><div class="cs"><div class="cs-n">20min</div><div class="cs-l">Avg completion time</div></div><div class="cs"><div class="cs-n">60%</div><div class="cs-l">More client invites</div></div></div><div class="cat-modal-jobs"><div class="job-item" onclick="showToast('Test started','React.js Advanced Assessment — 45 questions · 30 min')"><div class="job-item-ico">🔵</div><div class="job-item-body"><h4>React.js — Advanced</h4><p>45 questions covering hooks, context, performance optimization, and testing. Top 15% earn the "React Expert" badge.</p><div class="job-item-meta"><span class="jm g">Free</span><span class="jm">30 min</span><span class="jm">48K jobs require this skill</span></div></div></div><div class="job-item" onclick="showToast('Test started','Python — Data Science · 40 questions · 25 min')"><div class="job-item-ico">🐍</div><div class="job-item-body"><h4>Python — Data Science</h4><p>Covers pandas, NumPy, scikit-learn, SQL, and data visualization. Top scorers earn the "Data Expert" badge.</p><div class="job-item-meta"><span class="jm g">Free</span><span class="jm">25 min</span><span class="jm">27K jobs require this</span></div></div></div><div class="job-item" onclick="showToast('Test started','SEO Comprehensive · 60 questions · 40 min')"><div class="job-item-ico">📈</div><div class="job-item-body"><h4>SEO — Comprehensive</h4><p>Technical SEO, keyword research, on-page optimization, analytics. Partnered with Google Digital Academy.</p><div class="job-item-meta"><span class="jm g">Free</span><span class="jm">40 min</span><span class="jm">Google Certified</span></div></div></div><div class="job-item" onclick="showToast('Test started','AI & LLMs · 35 questions · 20 min')"><div class="job-item-ico">🤖</div><div class="job-item-body"><h4>AI Prompt Engineering</h4><p>LLM prompting, RAG concepts, AI tools, and model evaluation. Top 8% earn the "AI Certified" badge.</p><div class="job-item-meta"><span class="jm g">Free</span><span class="jm">20 min</span><span class="jm">18K jobs require this</span></div></div></div></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="showToast('Assessment center opened','Choose from 150+ skill tests to earn verified badges')">Browse all assessments →</button></div>`},
'agencies':{t:'Remoworkers Agencies',b:`<p style="color:#617a5a;font-size:14px;line-height:1.75;margin-bottom:20px">Hire a team with a lead contact who manages delivery. Agencies on Remoworkers are vetted, have shared ratings, and offer capacity you can scale up or down.</p><div class="search-results"><div class="sr-item" onclick="showToast('Agency profile opened','Pixel & Co. Design Agency — 8 members')"><div class="sr-av" style="background:#d1fae5;color:#065f46;font-size:12px">P&C</div><div class="sr-info"><h4>Pixel & Co. Design Agency</h4><p>UI/UX, Branding, Webflow · 8 team members · ★ 5.0 · 203 reviews</p><div class="sr-meta"><span class="sr-m">🇩🇪 Berlin</span><span class="sr-m">✓ Agency Verified</span><span class="sr-m">🟢 Accepting work</span></div></div><span class="sr-rate">From $75/hr</span></div><div class="sr-item" onclick="showToast('Agency profile opened','CodeCraft Engineering — 12 members')"><div class="sr-av" style="background:#dbeafe;color:#1e40af;font-size:12px">CC</div><div class="sr-info"><h4>CodeCraft Engineering</h4><p>React, Node.js, AWS, Mobile Apps · 12 team members · ★ 4.9 · 184 reviews</p><div class="sr-meta"><span class="sr-m">🇺🇸 Austin, TX</span><span class="sr-m">✓ Agency Verified</span></div></div><span class="sr-rate">From $110/hr</span></div><div class="sr-item" onclick="showToast('Agency profile opened','GrowthLab Marketing — 6 members')"><div class="sr-av" style="background:#fef3c7;color:#92400e;font-size:12px">GL</div><div class="sr-info"><h4>GrowthLab Marketing</h4><p>SEO, Paid Ads, Content, Analytics · 6 team members · ★ 4.8 · 97 reviews</p><div class="sr-meta"><span class="sr-m">🇬🇧 London</span><span class="sr-m">✓ Agency Verified</span></div></div><span class="sr-rate">From $55/hr</span></div></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="openModal('post-job')">Post a job for agencies →</button></div>`},
'work-type-freelance':{t:'Freelance Contracts',b:`<div style="background:#f7faf5;border:1.5px solid #dce8d8;border-radius:16px;padding:24px;margin-bottom:24px"><h3 style="font-size:17px;font-weight:700;margin-bottom:8px">The most flexible way to hire</h3><p style="font-size:14px;color:#617a5a;line-height:1.75">Hire for a specific project (fixed-price) or on an ongoing basis (hourly). No commitments, no overhead, no complexity.</p></div><div class="plan-cards"><div class="plan-c featured"><div class="plan-badge">Hourly</div><h3>Pay by the hour</h3><div class="plan-price" style="font-size:24px">Time-tracked</div><div class="plan-price-sub">Best for ongoing work</div><ul><li>Remoworkers time tracker included</li><li>Screenshot activity logs</li><li>Weekly automated billing</li><li>Uma Work Diary summaries</li><li>Dispute protection on all hours</li></ul><button class="btn btn-green plan-btn" onclick="openModal('post-job')">Post Hourly Job</button></div><div class="plan-c"><h3>Fixed Price</h3><div class="plan-price" style="font-size:24px">Milestone-based</div><div class="plan-price-sub">Best for defined projects</div><ul><li>Set milestones & deliverables</li><li>Escrow payment per milestone</li><li>Release on your approval only</li><li>Full refund if no milestone approved</li><li>Clear scope & expectations</li></ul><button class="btn btn-outline plan-btn" onclick="openModal('post-job')">Post Fixed-Price Job</button></div></div>`},
'work-type-fractional':{t:'Fractional Talent',b:`<div style="background:#16281a;border-radius:20px;padding:24px;margin-bottom:24px;text-align:center"><div style="font-size:40px;margin-bottom:12px">⚡</div><h3 style="font-family:'Instrument Serif',serif;font-size:22px;color:#c8f135;margin-bottom:8px">Senior expertise, part-time cost</h3><p style="color:rgba(255,255,255,.65);font-size:14px;line-height:1.7">A fractional hire works 10–30 hrs/week exclusively focused on your business — the strategic depth of a full-time executive at a fraction of the cost.</p></div><div class="cat-stats-row"><div class="cs"><div class="cs-n">60%</div><div class="cs-l">Less than FT salary</div></div><div class="cs"><div class="cs-n">10–30h</div><div class="cs-l">Weekly commitment</div></div><div class="cs"><div class="cs-n">C-suite</div><div class="cs-l">Level expertise</div></div></div><div class="cat-modal-jobs"><div class="job-item" onclick="showToast('Fractional CMO profiles','Showing 340 available CMOs')"><div class="job-item-ico">📈</div><div class="job-item-body"><h4>Fractional CMO</h4><p>Marketing strategy, brand positioning, go-to-market, and team leadership on a part-time basis.</p><div class="job-item-meta"><span class="jm g">$150–$300/hr</span><span class="jm">340 available</span></div></div></div><div class="job-item" onclick="showToast('Fractional CTO profiles','Showing 280 available CTOs')"><div class="job-item-ico">💻</div><div class="job-item-body"><h4>Fractional CTO</h4><p>Technical strategy, architecture decisions, team hiring, and engineering leadership.</p><div class="job-item-meta"><span class="jm g">$200–$400/hr</span><span class="jm">280 available</span></div></div></div><div class="job-item" onclick="showToast('Fractional CFO profiles','Showing 190 available CFOs')"><div class="job-item-ico">💰</div><div class="job-item-body"><h4>Fractional CFO</h4><p>Financial strategy, investor relations, fundraising prep, and financial modeling.</p><div class="job-item-meta"><span class="jm g">$175–$350/hr</span><span class="jm">190 available</span></div></div></div></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="openModal('post-job')">Post a Fractional Role →</button></div>`},
'work-type-payroll':{t:'Payroll Services',b:`<div style="background:#f7faf5;border:1.5px solid #dce8d8;border-radius:16px;padding:24px;margin-bottom:24px"><h3 style="font-size:17px;font-weight:700;margin-bottom:8px">Hire contractors as compliant W-2 employees</h3><p style="font-size:14px;color:#617a5a;line-height:1.75">Remoworkers Payroll handles employment taxes, benefits administration, workers' compensation, and legal compliance — so you can convert your best freelancers into full-time team members without the HR overhead.</p></div><div class="cat-modal-jobs"><div class="job-item" style="cursor:default"><div class="job-item-ico">🏛️</div><div class="job-item-body"><h4>Tax & compliance handling</h4><p>Remoworkers acts as the employer of record. We handle federal and state taxes, W-2 filing, Social Security, Medicare, and unemployment insurance.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">🏥</div><div class="job-item-body"><h4>Benefits administration</h4><p>Offer health, dental, vision, and 401(k) to your payrolled workers. Remoworkers partners with top benefits providers to handle enrollment and administration.</p></div></div><div class="job-item" style="cursor:default"><div class="job-item-ico">🔄</div><div class="job-item-body"><h4>Convert any freelancer</h4><p>Already working with a freelancer you love? Convert them to payrolled status in minutes — they keep their existing project context and work diary history.</p></div></div></div><div class="modal-actions"><button class="btn btn-green btn-full" onclick="showToast('Payroll inquiry sent','Our team will contact you within 24 hours')">Talk to Payroll Specialist</button></div>`}
};
Object.assign(M, NM);

window.showToast = showToast;
window.doSearch = doSearch;
window.searchFor = searchFor;
window.setF = setF;
window.toggleSave = toggleSave;
window.toggleDd = toggleDd;
window.switchTab = switchTab;
window.scrollToTop = scrollToTop;

document.querySelectorAll('.uma-grid>div').forEach(el=>io.observe(el));

if (window.__pendingAuthModal && typeof openModal === 'function') {
  openModal(window.__pendingAuthModal);
  window.__pendingAuthModal = null;
}
